import{_ as i,o as a,c as t,ag as n}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Open Tracking","description":"","frontmatter":{},"headers":[],"relativePath":"features/open-tracking.md","filePath":"features/open-tracking.md"}'),o={name:"features/open-tracking.md"};function s(r,e,l,c,d,p){return a(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="open-tracking" tabindex="-1">Open Tracking <a class="header-anchor" href="#open-tracking" aria-label="Permalink to &quot;Open Tracking&quot;">​</a></h1><p>Open tracking allows you to monitor when recipients open your emails. When enabled, SendGrail embeds an invisible tracking pixel in HTML emails and records each time it is loaded.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ol><li><p><strong>Pixel injection</strong> -- When an HTML email is sent, SendGrail injects an invisible 1x1 transparent GIF image just before the closing <code>&lt;/body&gt;</code> tag.</p></li><li><p><strong>Unique identifier</strong> -- Each email is assigned a unique UUID (<code>tracking_id</code>) that is embedded in the pixel URL.</p></li><li><p><strong>Tracking URL</strong> -- The pixel loads from your WordPress site:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/wp-json/sendgrail/v2/t/{tracking_id}</span></span></code></pre></div></li><li><p><strong>Open detection</strong> -- When the recipient&#39;s email client renders the email and loads images, the pixel URL is requested from your server.</p></li><li><p><strong>Event recording</strong> -- SendGrail records the following data for each open event:</p><ul><li>IP address</li><li>User-Agent string</li><li>Timestamp</li></ul></li><li><p><strong>Denormalized counts</strong> -- For fast access, the <code>open_count</code> and <code>opened_at</code> (first open timestamp) fields are stored directly on the email log entry.</p></li></ol><h2 id="conditions-and-limitations" tabindex="-1">Conditions and Limitations <a class="header-anchor" href="#conditions-and-limitations" aria-label="Permalink to &quot;Conditions and Limitations&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Open tracking relies on the recipient&#39;s email client loading remote images. Many email clients block images by default, so open tracking will <strong>undercount</strong> actual opens. Treat open rates as a lower-bound estimate, not an exact measurement.</p></div><ul><li><strong>HTML emails only</strong> -- Plain text emails do not support pixel injection. Open tracking is automatically skipped for plain text messages.</li><li><strong>Primary sends only</strong> -- The tracking pixel is injected only on the primary send attempt. Fallback attempts do not receive a separate pixel to avoid duplicate tracking.</li></ul><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>Open tracking is controlled by the <code>enable_open_tracking</code> setting in the plugin settings page. Toggle it on or off as needed.</p><p>When disabled, no tracking pixel is injected into outgoing emails and no open events are recorded.</p><h2 id="viewing-open-data" tabindex="-1">Viewing Open Data <a class="header-anchor" href="#viewing-open-data" aria-label="Permalink to &quot;Viewing Open Data&quot;">​</a></h2><p>Open tracking data is available in the <a href="/features/email-logging#email-report-view">email report view</a> for each individual email:</p><ul><li><strong>Open count</strong> -- Total number of times the tracking pixel was loaded</li><li><strong>First opened</strong> -- Timestamp of the first recorded open</li><li><strong>Event timeline</strong> -- Chronological list of all open events with IP, User-Agent, and timestamp</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Multiple opens from the same recipient are counted individually. A high open count on a single email may indicate the recipient opened it multiple times or that the email was forwarded.</p></div><h2 id="privacy-considerations" tabindex="-1">Privacy Considerations <a class="header-anchor" href="#privacy-considerations" aria-label="Permalink to &quot;Privacy Considerations&quot;">​</a></h2><p>Open tracking collects IP addresses and User-Agent strings. Ensure that your use of open tracking complies with applicable privacy regulations (such as GDPR or CCPA) and that your site&#39;s privacy policy discloses email tracking practices where required.</p>',16)])])}const m=i(o,[["render",s]]);export{h as __pageData,m as default};
